import{_ as a,o as e,c as t,ae as n}from"./chunks/framework.B6gjLfeO.js";const _=JSON.parse('{"title":"旁路由 OpenClash 透明代理配置避坑","description":"","frontmatter":{},"headers":[],"relativePath":"tools/openclash-proxy.md","filePath":"tools/openclash-proxy.md"}'),r={name:"tools/openclash-proxy.md"};function s(l,o,i,p,c,h){return e(),t("div",null,[...o[0]||(o[0]=[n('<h1 id="旁路由-openclash-透明代理配置避坑" tabindex="-1">旁路由 OpenClash 透明代理配置避坑 <a class="header-anchor" href="#旁路由-openclash-透明代理配置避坑" aria-label="Permalink to &quot;旁路由 OpenClash 透明代理配置避坑&quot;">​</a></h1><h2 id="网络拓扑前提" tabindex="-1">网络拓扑前提 <a class="header-anchor" href="#网络拓扑前提" aria-label="Permalink to &quot;网络拓扑前提&quot;">​</a></h2><p>如果你希望局域网内的设备（如 Windows 主控机、虚拟机）<strong>不开启任何代理软件就能直接翻墙（透明代理）</strong>，需要满足以下条件。</p><h2 id="核心配置步骤" tabindex="-1">核心配置步骤 <a class="header-anchor" href="#核心配置步骤" aria-label="Permalink to &quot;核心配置步骤&quot;">​</a></h2><ol><li><p><strong>指向网关和 DNS</strong>： 将需要透明代理的设备的 <strong>默认网关</strong> 和 <strong>首选 DNS</strong> 均手动指向你的旁路由 IP（例如：<code>192.168.1.2</code>）。</p><blockquote><p>Linux (如 Ubuntu 虚拟机) 同样需要在 Netplan 或 NetworkManager 中修改。如果不改，AI 或部分命令行工具会因无法连通外网而报错。</p></blockquote></li><li><p><strong>OpenClash 设置</strong>：</p><ul><li>必须处于 <strong>Fake-IP 模式</strong>。</li><li>旁路由的防火墙（lan 区域）必须开启 <strong>IP 动态伪装 (MASQUERADE)</strong>，否则流量无法正常转发。</li></ul></li><li><p><strong>HTTP 407 认证拦截（关键大坑）</strong>： 如果你的 OpenClash 开启了“局域网共享”，<strong>必须确保关闭“HTTP 代理端口认证”</strong>（即不要设置账号密码）。否则局域网内的流量会被静默拦截，设备彻底断网且很难排查原因。</p></li></ol><h2 id="备选安全方案" tabindex="-1">备选安全方案 <a class="header-anchor" href="#备选安全方案" aria-label="Permalink to &quot;备选安全方案&quot;">​</a></h2><p>如果你不想动全局网关和 DNS（怕把网络搞崩），最稳妥的排查方式是：在系统设置或浏览器中，手动将 HTTP/HTTPS 代理指向旁路由的 7890 端口（如 <code>192.168.1.2:7890</code>）。这样既能翻墙，又完全不影响局域网的内网通信。</p>',7)])])}const g=a(r,[["render",s]]);export{_ as __pageData,g as default};
